#include "controller.h"

#include <stdbool.h>
#include <stddef.h>

static bool controller_sensor_stale(uint32_t now_ms, bool seen_valid, uint32_t last_ms)
{
    return seen_valid && ((uint32_t) (now_ms - last_ms) > CONTROLLER_SENSOR_TIMEOUT_MS);
}

static bool controller_outputs_equal(const controller_t *controller, bool compressor_on, bool vent_open)
{
    if (controller == NULL) {
        return false;
    }

    return (controller->compressor_on == compressor_on) && (controller->vent_open == vent_open);
}

static controller_output_t controller_make_output(const controller_t *controller, bool timed_out)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_ENUM_SAFE_VENT,
        .state_name = CONTROLLER_STATE_SAFE_VENT,
        .changed = true,
        .timed_out = timed_out,
    };

    if (controller == NULL) {
        return output;
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = false;
    return output;
}

static void controller_set_output(controller_t *controller, bool compressor_on, bool vent_open, controller_state_t state)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = compressor_on;
    controller->vent_open = vent_open;
    controller->state = state;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_ENUM_SAFE_VENT;
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output;
    bool had_valid_pressure;
    bool had_valid_door;
