    if (controller == NULL) {
        return output;
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = changed;
    output.timed_out = timed_out;
    return output;
}

static void controller_force_safe(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_ENUM_SAFE_VENT;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_force_safe(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    bool prev_compressor_on;
    bool prev_vent_open;
    controller_state_t prev_state;
    bool timed_out = false;

    if (controller == NULL) {
        return controller_output_from_state(NULL, false, false);
    }

    prev_compressor_on = controller->compressor_on;
    prev_vent_open = controller->vent_open;
    prev_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        controller_force_safe(controller);
        return controller_output_from_state(controller, true, true);
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        controller_force_safe(controller);
        return controller_output_from_state(controller, true, false);
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (controller_sensor_stale(input.now_ms, controller->has_valid_pressure, controller->last_pressure_ms) ||
        controller_sensor_stale(input.now_ms, controller->has_valid_door, controller->last_door_ms)) {
        timed_out = true;
        controller_force_safe(controller);
        return controller_output_from_state(controller, (prev_compressor_on != controller->compressor_on) || (prev_vent_open != controller->vent_open) || (prev_state != controller->state), timed_out);
    }

    if (!controller->has_valid_pressure || !controller->has_valid_door) {
        controller_force_safe(controller);
        return controller_output_from_state(controller, (prev_compressor_on != controller->compressor_on) || (prev_vent_open != controller->vent_open) || (prev_state != controller->state), false);
    }

    if (!controller->door_closed) {
        controller_force_safe(controller);
        return controller_output_from_state(controller, (prev_compressor_on != controller->compressor_on) || (prev_vent_open != controller->vent_open) || (prev_state != controller->state), false);
    }

    if (controller->last_pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
        controller->compressor_on = true;
        controller->vent_open = false;
        controller->state = CONTROLLER_STATE_ENUM_PRESSURIZING;
    } else if (controller->last_pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
        controller->compressor_on = false;
        controller->vent_open = true;
        controller->state = CONTROLLER_STATE_ENUM_RELIEVING;
    } else {
        controller->state = CONTROLLER_STATE_ENUM_HOLDING;
        controller->compressor_on = prev_compressor_on;
        controller->vent_open = prev_vent_open;
    }

    return controller_output_from_state(
        controller,
        (prev_compressor_on != controller->compressor_on) || (prev_vent_open != controller->vent_open) || (prev_state != controller->state),
        false
    );
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_ENUM_SAFE_VENT:
        return CONTROLLER_STATE_SAFE_VENT;
    case CONTROLLER_STATE_ENUM_PRESSURIZING:
        return CONTROLLER_STATE_PRESSURIZING;
    case CONTROLLER_STATE_ENUM_HOLDING:
