def _assert_no_forbidden_pair(self, lines: list[str]) -> None:
    compressor_on = False
    vent_open = False
    for line in lines:
        if line == "ACT COMPRESSOR ON":
            compressor_on = True
        elif line == "ACT COMPRESSOR OFF":
            compressor_on = False
        elif line == "ACT VENT OPEN":
            vent_open = True
        elif line == "ACT VENT CLOSED":
            vent_open = False
        self.assertFalse(
            compressor_on and vent_open,
            msg=f"forbidden actuator combination observed after line: {line!r}",
        )

